win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;

    const range = win.lastHighlightedRange;
    // Find the actual span element that contains our selection to get its 'bottom' coordinate
    let anchorSpan = range.startContainer.parentElement;
    while (anchorSpan && !anchorSpan.style.bottom) anchorSpan = anchorSpan.parentElement;

    if (!anchorSpan) return false;

    const SPLIT_Y = parseFloat(anchorSpan.style.bottom);
    const GAP = 350; 

    const page = anchorSpan.closest('.page');
    const container = page.querySelector('.text-container');

    if (doc.querySelector('.in-book-widget')) win.closeMironWidget();

    // SHIFT LOGIC: Move everything physically below the selection further down
    container.querySelectorAll('span, div').forEach(el => {
        if (el.classList.contains('in-book-widget')) return;
        const bVal = parseFloat(el.style.bottom);
        if (!isNaN(bVal) && bVal < SPLIT_Y) {
            if (!el.dataset.orgBottom) el.dataset.orgBottom = el.style.bottom;
            el.classList.add('shifting-text');
            el.style.bottom = (bVal - GAP) + 'px';
        }
    });

    // Expand Page Height
    const currentH = parseFloat(page.style.height);
    if (!page.dataset.orgHeight) page.dataset.orgHeight = page.style.height;
